args.sparql:
SELECT ?winner WHERE {
  ?event wdt:P31 wd:Q1207188 ;
         rdfs:label "Korea Open"@en ;
         wdt:P585 ?event_date .
  FILTER (YEAR(?event_date) = 2017) .
  ?event wdt:P527 ?singles .
  ?singles rdfs:label "Women's singles"@en .
  ?singles wdt:P3866 ?winner .
}

SELECT ?winner WHERE {
  ?event wdt:P31 wd:Q38059 ;  # tournament
         rdfs:label "Korea Open"@en ;
         wdt:P585 ?event_date .
  FILTER (YEAR(?event_date) = 2017) .
  ?event wdt:P527 ?singlesEvent .
  ?singlesEvent rdfs:label "Women's singles"@en ;
                wdt:P2550 ?winner .
}
